let incode,session,container=document.getElementById("incode-container");function notifyCompletion(e){const n=new CustomEvent("incodeCompleted",{detail:e});window.dispatchEvent(n)}function waitForIncode(e=50){return new Promise((n,o)=>{const t=setInterval(()=>{window.OnBoarding?(clearInterval(t),n(window.OnBoarding)):e--<=0&&(clearInterval(t),o(new Error("Incode SDK not loaded")))},100)})}async function init(){session={token:document.getElementById("incode-config").value},console.log(session);const e=await waitForIncode();incode=await e.create({apiURL:"https://demo-api.incodesmile.com/0"}),await sendGeo()}async function sendGeo(){await incode.sendFingerprint({token:session.token}).catch(console.error),await incode.sendGeolocation({token:session.token}).catch(console.error),renderID()}function renderID(){incode.renderCaptureId(container,{session:session,onSuccess:renderFace,onError:console.error})}function renderFace(){incode.renderCaptureFace(container,{session:session,onSuccess:doFaceMatch,onError:console.error})}async function doFaceMatch(){await incode.processFace({token:session.token}),await incode.processId({token:session.token}),notifyCompletion({token:session.token,status:"completed"})}function waitForContainer(){document.getElementById("incode-container")?init():setTimeout(waitForContainer,100)}"loading"===document.readyState?document.addEventListener("DOMContentLoaded",waitForContainer):waitForContainer();